import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as o,e as t}from"./app-72c1d60f.js";const r={},h=t('<h1 id="三体" tabindex="-1"><a class="header-anchor" href="#三体" aria-hidden="true">#</a> 三体</h1><h2 id="三体i" tabindex="-1"><a class="header-anchor" href="#三体i" aria-hidden="true">#</a> 三体I</h2><h3 id="序言" tabindex="-1"><a class="header-anchor" href="#序言" aria-hidden="true">#</a> 序言</h3><blockquote><p>人类之所以能够超越地球上的其它物种建立文明，主要是因为他们能够在自己的大脑中创造出现实不存在的东西，在未来，当人工智能拥有超过人类的智力时，想象力也许是我们对于它们所拥有的惟一优势。</p></blockquote><p>推荐两部科幻小说</p><ul><li><p>2001：A Space Odyssey (2001太空漫游) 目前可在腾讯视频观看电影版</p></li><li><p>Rendezvous With Rama</p></li></ul><h3 id="第一章-科学边界" tabindex="-1"><a class="header-anchor" href="#第一章-科学边界" aria-hidden="true">#</a> 第一章 科学边界</h3><blockquote><p>大部分人的人生都是偶然，是的，整个人类历史也是偶然，从石器时代到今天都没什么重大突破，真幸运。但既然是幸运总有结束的一天。</p></blockquote><h3 id="第二章-台球" tabindex="-1"><a class="header-anchor" href="#第二章-台球" aria-hidden="true">#</a> 第二章 台球</h3><blockquote><p>物理规律在时间和空间上是均匀的</p></blockquote><h3 id="第三章-射手和农场主" tabindex="-1"><a class="header-anchor" href="#第三章-射手和农场主" aria-hidden="true">#</a> 第三章 射手和农场主</h3><blockquote><p>射手假说：有一名神枪手，在一个靶子上每隔十厘米打一个洞。设想这个靶子的平面上生活着一种二维智能生物，它们中的科学家在对自己的宇宙进行观察后，发现了一个伟大的定律：“宇宙每隔10厘米，必然会有一个洞。”它们把这个神枪手一时兴起的随意行为，看成了自己宇宙中的铁律。<br> 农场主假说：一个农场里有一群火鸡，农场主每天中午11点来给它们喂食。火鸡中的一名科学家观察这个现象一年了都没有例外，于是它也发现了一个伟大的定律：“每天中午11点，就会有食欲降临。”它在感恩节早晨向火鸡们公布了这个定律，但这天上午11点没有食物降临，农场主进来把它们都捉去杀了。</p></blockquote><p>人类存在的时间只是200万年左右，宇宙存在的时间为140亿年左右，相比而言，人类科技发展时间在宇宙中的尺度是非常微小的。迄今为止人类的一切认知均建立在自己文明的经验学说之上。我们没有足够具有说服力的证据证明人类认为的科学是这个庞大宇宙中的真理。这是人类认知上的局限性，文明的等级差距在这两个假说上体现得淋漓尽致。我们是否又只是一种三维智能生物亦或者是火鸡呢？</p><h3 id="第四章-三体、周文王、长夜" tabindex="-1"><a class="header-anchor" href="#第四章-三体、周文王、长夜" aria-hidden="true">#</a> 第四章 三体、周文王、长夜</h3><blockquote><p>第137号文明结束了</p></blockquote><h3 id="第五章-叶文洁" tabindex="-1"><a class="header-anchor" href="#第五章-叶文洁" aria-hidden="true">#</a> 第五章 叶文洁</h3><blockquote><p>有两幅图。一幅是画面庞杂精细的《清明上河图》，另一幅是一张空旷的天空照片，空荡荡的蓝天上只有一缕似有似无的白云。教授问这两幅画中哪一幅所包含的信息量更大，答案是后者要比前者大一至两个数量级！</p></blockquote><p>如何理解呢？先看看下面这个故事！</p><h4 style="text-align:center;">最孤独的人</h4><blockquote><p>​ 1969年7月20日，迈克尔科林斯突然成了全世界最孤独的人。</p><p>​ 科林斯是执行“阿波罗11号“登月任务的三名美国宇航员之一，他的任务是呆在&quot;哥伦比亚号”指令舱中绕月球飞行，直到指令长尼尔•阿姆斯特朗和登月舱驾驶员巴兹•奥尔德林完成任务归来。</p><p>​ 这意味着科林斯无法成为首批登陆月球的人，他的名字不会像那两位同伴一样被铭记。</p><p>​ 当阿姆斯特朗和奥尔德林乘坐的“鹰号&quot;登月舱旋转着飞向月球表面的着陆点时，科林斯抓起手边的相机，拍下了一张照片。</p><p>​ 照片背景中那颗小小的蓝色星球上，有6.5亿人正在观看登月直播，他们即将见证阿姆斯特朗代表人类在太空探索史上迈出的一大步。</p><p>​ 科林斯当时不曾想到，当他按下快门那一刻，便留下了一张全世界古往今来所有人的大合影，只有他自己不在其中。</p><p>​ 根据质星守恒定律，无论是在这张照片拍摄前去世的人，还是在它拍摄后出生的人，构成他们的物质都被收罗在这张照片中，只是实体形式有可能发生变化，这就是所谓的质量既不能被创造也不能被<br> 破坏。</p><p>​ 这是科林斯第二次也是最后一次太空任务，他独自在&quot;哥伦比亚号”上等待了21个半小时,每当指令舱飞到月球背面，他和地球的通讯都要中断48分钟。在漫长的等待中，科林斯除了清理维护机舱等待两名队友的回归，剩下的时间都在孤独煎熬。<br> ​ &quot;我并不否认有孤独的感觉&quot;，科林斯后来说，&quot;特别是和地球中断联系的时候，那种孤独感格外强烈。我是真正的孤身一人，与任何已知的生命完全隔绝，月球那边是36亿人，月球这边只有我自己。</p><p>​ 柯林斯在2021年4月28日以90岁高龄去世，他在去世前几年接受采访时曾示，当时他非常担心阿姆斯<br> 特朗和奥尔德林的安全，如果他们不幸死在月球上，那么他将独自返航。</p><p>​ 假如那样的悲剧发生，科林斯作为唯一幸存者必将抱憾终身， 但同时他的名字也会举世皆知，而不<br> 是被媒体戏称为&quot;被遗忘的宇航员&quot;。</p></blockquote><h3 id="第六章-红岸之二" tabindex="-1"><a class="header-anchor" href="#第六章-红岸之二" aria-hidden="true">#</a> 第六章 红岸之二</h3><blockquote><p>&quot;西方资产阶级的奢侈玩意儿，用微波被吸收后产生的热效应加热食物。我以前在的那个研究所，为了精密测试某种元件的高温老化，从国外进口了一台。我们下了班也用它热馒头、烤土豆。很有意思，里面先热，外头还是凉的。&quot;雷政委说着站了起来，来回踱步，他走得如此贴近悬崖边缘，令叶文洁十分紧张，&quot;红岸系统就是一台微波炉，加热的目标是敌人在太空中的航天器。只要达到0.1～1瓦/平方厘米的微波能量辐射，就可直接使卫星通信、雷达、导航等系统的微波电子设备失效或烧毁。&quot;</p></blockquote><p>微波炉热东西都是从里到外热的吗？其实不尽然，基本来说微波炉是以加快分子运动的方式来加热的，其中对水分子的效果最强。微波炉加热的范围跟水分子的分布很有关系，如果有很多水分子在内部，那么的确是从里面开始加热的，如果有很多水分子在外面那么很多能量会被这些水分子吸收。传递到内部已经没有多少能量了。而且微波一般来说只能穿透两公分左右的食物，如果物体过大，很有可能只有两公分的表皮部分被加热，剩下的中心部分需要热传导来加热。</p>',23),d=[h];function c(i,p){return a(),o("div",null,d)}const l=e(r,[["render",c],["__file","三体.html.vue"]]);export{l as default};
